import { z } from "zod";

/**
 * SINGLE SOURCE OF TRUTH for the page builder.
 *
 * Each block is a Zod object whose `type` literal is the discriminator that both
 * Decap CMS (the "variable type" list widget) and Astro use to tell blocks apart.
 *
 * From these schemas we derive:
 *   - the Astro content collection schema (src/content.config.ts)
 *   - the Decap CMS config (public/config.yml), generated by introspecting Zod
 *     internals — see src/lib/generate-config.ts
 *
 * To add a field, edit it here once. To add a new block: add a schema below,
 * include it in `blockSchemas`, and add a matching component to the registry in
 * src/blocks/index.ts.
 */

export const block1 = z.object({
  type: z.literal("block1"),
  title: z.string(),
  description: z.string(),
  // A rich-text field. `.meta({ widget })` overrides the default string widget,
  // so Decap renders a markdown editor and stores markdown source in the JSON.
  // Optional so pages authored before this field existed still validate; the
  // generator emits `required: false` in the Decap config.
  body: z.string().meta({ widget: "markdown" }).optional(),
});

export const block2 = z.object({
  type: z.literal("block2"),
  title: z.string(),
  description: z.string(),
});

export const block3 = z.object({
  type: z.literal("block3"),
  title: z.string(),
  description: z.string(),
});

/**
 * Embeds a p5.js sketch. The sketch is authored as a file under
 * src/content/sketches/ and referenced here by filename, rather than pasted as
 * code: a sketch runs as JavaScript on the site's own origin, so the set of
 * runnable sketches stays reviewable in git instead of being editable from the
 * CMS. Editors choose from the sketches that exist; adding a new one is a PR.
 */
export const p5Sketch = z
  .object({
    type: z.literal("p5sketch"),
    // `optionsFrom: "sketches"` fills the dropdown from the filenames in
    // src/content/sketches at build time, so the CMS offers exactly the
    // sketches that exist on disk.
    sketch: z
      .string()
      .meta({ widget: "select", label: "Sketch", optionsFrom: "sketches" }),
    title: z.string().optional(),
    caption: z.string().optional(),
    // Intrinsic canvas size. The rendered canvas is scaled down responsively to
    // fit narrow viewports, so treat these as an aspect ratio + max size.
    width: z.number().optional(),
    height: z.number().optional(),
  })
  // humanize() would render "p5sketch" as "P 5sketch"; name it explicitly.
  .meta({ label: "p5.js Sketch" });

/** All block schemas, in the order they appear in the CMS "add block" menu. */
export const blockSchemas = [block1, block2, block3, p5Sketch] as const;

/** The `blocks` list: any block, any order, repeatable. */
export const blocksUnion = z.discriminatedUnion("type", [
  block1,
  block2,
  block3,
  p5Sketch,
]);

/** A full page definition. */
export const pageSchema = z.object({
  title: z.string(),
  slug: z.string(),
  blocks: z.array(blocksUnion),
});

/** Convenience types for components. */
export type Page = z.infer<typeof pageSchema>;
export type Block = z.infer<typeof blocksUnion>;
export type BlockType = Block["type"];

/**
 * Decap CMS collection definition. `schema` drives the generated fields; the rest
 * is collection-level config Zod can't express. Consumed by src/lib/generate-config.ts.
 */
export const pagesCms = {
  name: "pages",
  label: "Pages",
  folder: "src/content/pages",
  create: true,
  delete: true,
  identifier_field: "title",
  extension: "json",
  format: "json",
  slug: "{{fields.slug}}",
  schema: pageSchema,
};
